mapper.select:
SELECT MAX(CASE WHEN rp.permission_code = 'k3_add' THEN 'k3_add' END) AS k3Add, MAX(CASE WHEN rp.permission_code = 'k3_edit' THEN 'k3_edit' END) AS k3Edit, MAX(CASE WHEN rp.permission_code = 'k3_delete' THEN 'k3_delete' END) AS k3Delete, MAX(CASE WHEN rp.permission_code = 'k3_myedit' THEN 'k3_myedit' END) AS k3Myedit, MAX(CASE WHEN rp.permission_code = 'k3_comment' THEN 'k3_comment' END) AS k3Comment FROM members m JOIN member_roles mr ON m.member_id = mr.member_id JOIN roles r ON mr.role_id = r.role_id JOIN role_permissions rp ON r.role_id = rp.role_id WHERE m.user_code = #{userCode}
AND m.project_id = #{pId}
AND rp.permission_code IN ('k3_add', 'k3_edit', 'k3_delete', 'k3_myedit', 'k3_comment')
